previewCss:
.darma-loader-darma-custom-644 {color: var(--loader-color, #94a3b8);
  --loader-secondary-color: #cbd5e1;
  --loader-bg: #f8fafc;

  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 10px;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644-avatar,
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644-line {
  background: color-mix(in srgb, var(--loader-color, #94a3b8) 65%, var(--loader-bg, #f8fafc));
  animation: darma-loader-darma-custom-644-skeletonPulse var(--loader-speed, 1.2s) ease-in-out infinite;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644-avatar {
  width: 48px;
  height: 48px;
  border-radius: 999px;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644-lines {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644-line {
  height: 20px;
  border-radius: 999px;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644-line-short { width: 112px; }
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644-line-long { width: 144px; }
@keyframes darma-loader-darma-custom-644-skeletonPulse {
  0%, 100% { opacity: .45; }
  50% { opacity: 1; }
}

